"use client"

import { ArrowRight } from "lucide-react"

export function ProjectsSection() {
  return (
    <section id="projects" className="section-container relative border-t border-white/5">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-0">
        {/* Left Column: Label */}
        <div className="lg:col-span-4">
          <div className="sticky top-24">
            <span className="editorial-label block mb-2 opacity-50">04_SHOWCASE</span>
            <h2 className="uppercase">Projects</h2>
          </div>
        </div>

        {/* Right Column: Projects */}
        <div className="lg:col-span-8 space-y-24">
          <div className="reveal-anim">
            <div className="group cursor-pointer">
              <span className="editorial-label block mb-4 opacity-30">01 // [CASE_STUDY]</span>
              <div className="relative aspect-[16/9] bg-white/[0.03] border border-white/5 overflow-hidden mb-8">
                <img 
                  src="/images/project-1.png" 
                  alt="Project visual" 
                  className="w-full h-full object-cover opacity-80 group-hover:opacity-100 group-hover:scale-105 transition-all duration-1000"
                />
              </div>
              
              <div className="flex justify-between items-end">
                <div className="max-w-md">
                  <h3 className="text-2xl uppercase mb-2">Technical Dossier</h3>
                  <p className="text-sm text-muted-foreground">
                    A comprehensive study of frontend architecture and micro-interactions.
                  </p>
                </div>
                <div className="flex items-center gap-2 group-hover:translate-x-2 transition-transform">
                  <span className="border-b border-white text-[10px] uppercase tracking-widest pb-1">
                    Details
                  </span>
                  <ArrowRight className="w-4 h-4" />
                </div>
              </div>
            </div>
          </div>

          <div className="reveal-anim" style={{ animationDelay: "200ms" }}>
            <div className="group cursor-pointer opacity-40 hover:opacity-100 transition-opacity">
              <span className="editorial-label block mb-4 opacity-30">02 // [UPCOMING]</span>
              <div className="flex justify-between items-center py-12 border-y border-white/5">
                <h3 className="text-4xl uppercase">Future Artifacts</h3>
                <div className="flex items-center gap-2">
                  <span className="editorial-label">Q3 2025</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Decorative vertical line */}
      <div className="vertical-rhythm-line left-1/3 opacity-5 hidden lg:block"></div>
    </section>
  )
}

