"use client"

import { useState, useEffect } from "react"

export function LoadingScreen({ onLoadingComplete }: { onLoadingComplete: () => void }) {
  const [progress, setProgress] = useState(0)

  useEffect(() => {
    const progressInterval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(progressInterval)
          setTimeout(onLoadingComplete, 800)
          return 100
        }
        return prev + Math.random() * 20
      })
    }, 120)

    return () => clearInterval(progressInterval)
  }, [onLoadingComplete])

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black">
      <div className="relative flex flex-col items-center">
        <span className="editorial-label absolute -top-12 opacity-30 animate-pulse">
          SYSTEM_BOOT_ARCHIVE_024
        </span>
        
        <h1 className="text-[15vw] leading-none font-medium tracking-tighter tabular-nums">
          {Math.min(Math.round(progress), 100)}
        </h1>

        <div className="absolute -bottom-12 w-64 h-px bg-white/10 overflow-hidden">
          <div 
            className="h-full bg-white transition-all duration-300 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>
    </div>
  )
}

