"use client"

export function QuoteSection() {
    return (
        <section className="section-container relative bg-white/[0.02]">
            <div className="absolute top-12 left-12">
                <span className="editorial-label opacity-40">02_PHILOSOPHY</span>
            </div>

            <div className="max-w-5xl mx-auto px-6 text-center">
                <blockquote className="reveal-anim">
                    <h2 className="text-4xl md:text-6xl lg:text-7xl leading-[1.1] uppercase font-medium">
                        "Design is the<br />
                        silent ambassador<br />
                        <span className="opacity-30">of your brand."</span>
                    </h2>
                    
                    <footer className="mt-12">
                        <cite className="editorial-label opacity-50 not-italic block mb-2">Paul Rand</cite>
                        <span className="text-[10px] uppercase tracking-widest opacity-20">Graphic Designer</span>
                    </footer>
                </blockquote>
            </div>

            {/* Decorative hairlines */}
            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-px h-12 bg-white/10"></div>
            <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-px h-12 bg-white/10"></div>
        </section>
    )
}

