"use client"

import { motion } from "framer-motion"

export function AboutSection() {
  return (
    <section id="about" className="section-container relative border-t border-white/5">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-0">
        {/* Left Column: Label */}
        <div className="lg:col-span-4">
          <div className="sticky top-24">
            <span className="editorial-label block mb-2 opacity-50">01_PROFILE</span>
            <h2 className="uppercase">About</h2>
          </div>
        </div>

        {/* Right Column: Narrative */}
        <div className="lg:col-span-8 space-y-12">
          {/* Featured Visual */}
          <div className="relative aspect-[16/6] overflow-hidden border border-white/5 reveal-anim mb-12">
            <img 
              src="/images/about-visual.png" 
              alt="Architectural abstraction" 
              className="w-full h-full object-cover grayscale hover:grayscale-0 transition-all duration-700"
            />
            <div className="absolute inset-0 bg-black/20" />
          </div>

          <div className="max-w-2xl reveal-anim">
            <p className="text-xl md:text-2xl text-white leading-tight mb-8">
              I am a developer who cares deeply about the intersection of aesthetics and performance. 
              Based in Lagos, I specialize in building digital artifacts that are as functional as they are memorable.
            </p>
            
            <div className="space-y-6 text-muted-foreground">
              <p>
                My journey in the web ecosystem has led me through startups, designer collaborations, and institutional projects. 
                In every case, my priority remains the same: crafting pixel-perfect interfaces that feel intuitive and alive.
              </p>
              <p>
                Currently, I am focused on the JavaScript ecosystem—specifically React and Next.js—to push the boundaries 
                of what's possible on the modern web.
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-3 gap-8 pt-12 border-t border-white/5">
            <div>
              <span className="editorial-label block mb-4 opacity-30">Stack</span>
              <ul className="space-y-2 font-mono text-[11px] uppercase tracking-wider">
                <li>TypeScript</li>
                <li>React / Next.js</li>
                <li>Tailwind CSS</li>
              </ul>
            </div>
            <div>
              <span className="editorial-label block mb-4 opacity-30">Tools</span>
              <ul className="space-y-2 font-mono text-[11px] uppercase tracking-wider">
                <li>Framer Motion</li>
                <li>Shadcn UI</li>
                <li>Figma</li>
              </ul>
            </div>
            <div className="hidden md:block">
              <span className="editorial-label block mb-4 opacity-30">Vibe</span>
              <ul className="space-y-2 font-mono text-[11px] uppercase tracking-wider">
                <li>Minimalist</li>
                <li>Precision</li>
                <li>Archive-First</li>
              </ul>
            </div>
          </div>
        </div>
      </div>

      {/* Decorative vertical line */}
      <div className="vertical-rhythm-line left-1/3 opacity-5 hidden lg:block"></div>
    </section>
  )
}

