"use client"

import { useEffect, useState } from "react"
import { ArrowRight } from "lucide-react"

export function HeroSection() {
  const [isLoaded, setIsLoaded] = useState(false)

  useEffect(() => {
    setIsLoaded(true)
  }, [])

  return (
    <section id="hero" className="section-container relative overflow-hidden bg-black">
      {/* Background Texture */}
      <div className="absolute inset-0 z-0">
        <img 
          src="/images/hero-bg.png" 
          alt="" 
          className="w-full h-full object-cover opacity-60 scale-110 animate-pulse-subtle"
        />
        <div className="absolute inset-0 bg-gradient-to-b from-black via-transparent to-black opacity-80" />
      </div>

      {/* Side-rail indicator */}
      <div className="absolute left-6 top-1/2 -translate-y-1/2 hidden lg:block z-10">
        <span className="editorial-label [writing-mode:vertical-lr] opacity-40">
          PORTFOLIO_024 // LAGOS_NGR
        </span>
      </div>

      <div className="flex flex-col items-center text-center max-w-4xl mx-auto px-4">
        <div className={`space-y-8 ${isLoaded ? "reveal-anim" : "opacity-0"}`}>
          <span className="editorial-label block mb-4">
            Building Digital Artifacts
          </span>
          
          <h1 className="leading-[0.85] uppercase">
            Yinka<br />
            <span className="opacity-40">Salaam</span>
          </h1>

          <p className="text-lg md:text-xl max-w-lg mx-auto leading-relaxed">
            Focused on creating exceptional digital experiences that blend thoughtful design with robust engineering.
          </p>

          <div className="pt-12">
            <a
              href="#projects"
              className="inline-flex items-center gap-4 group text-sm font-medium tracking-widest uppercase"
            >
              <span className="border-b border-white pb-1 group-hover:opacity-60 transition-opacity">
                View Archive
              </span>
              <ArrowRight className="w-4 h-4 group-hover:translate-x-2 transition-transform" />
            </a>
          </div>
        </div>
      </div>

      {/* Decorative Rhythm Lines */}
      <div className="vertical-rhythm-line left-12 opacity-20 hidden md:block"></div>
      <div className="vertical-rhythm-line right-12 opacity-20 hidden md:block"></div>
      
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2">
        <span className="editorial-label opacity-40 animate-pulse">
          Scroll to Explore
        </span>
      </div>
    </section>
  )
}

